import React from 'react';

const Card = ({ children, className, title, action, subtitle, icon: Icon, hover = true }) => {
  return (
    <div className={`group relative bg-white/95 backdrop-blur-md rounded-2xl border border-gray-200/50 shadow-lg hover:shadow-xl transition-all duration-300 ${
      hover ? 'hover:-translate-y-1' : ''
    } ${className || ''}`}>
      {/* Shimmer effect */}
      <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000 ease-out rounded-2xl"></div>
      {/* Background decoration with portal-specific themes */}
      <div className="absolute inset-0 bg-gradient-to-br from-gray-50/50 via-blue-50/50 to-indigo-50/50 rounded-2xl"></div>

      {/* Portal-specific background decorations */}
      <div className="portal-admin absolute inset-0 bg-gradient-to-br from-purple-50/50 via-indigo-50/50 to-blue-50/50 rounded-2xl"></div>
      <div className="portal-teacher absolute inset-0 bg-gradient-to-br from-blue-50/50 via-cyan-50/50 to-indigo-50/50 rounded-2xl"></div>
      <div className="portal-student absolute inset-0 bg-gradient-to-br from-green-50/50 via-emerald-50/50 to-teal-50/50 rounded-2xl"></div>

      {/* Animated gradient orbs */}
      <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-blue-400/10 to-indigo-400/10 rounded-full blur-2xl group-hover:opacity-30 transition-all duration-500 group-hover:scale-110"
        style={{
          transform: 'translate(30%, -30%)'
        }}
      />
      <div className="portal-admin absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-purple-400/10 to-indigo-400/10 rounded-full blur-2xl group-hover:opacity-30 transition-all duration-500 group-hover:scale-110"
        style={{
          transform: 'translate(30%, -30%)'
        }}
      />
      <div className="portal-teacher absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-blue-400/10 to-cyan-400/10 rounded-full blur-2xl group-hover:opacity-30 transition-all duration-500 group-hover:scale-110"
        style={{
          transform: 'translate(30%, -30%)'
        }}
      />
      <div className="portal-student absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-green-400/10 to-emerald-400/10 rounded-full blur-2xl group-hover:opacity-30 transition-all duration-500 group-hover:scale-110"
        style={{
          transform: 'translate(30%, -30%)'
        }}
      />

      <div className="absolute bottom-0 left-0 w-24 h-24 bg-gradient-to-tr from-cyan-400/10 to-blue-400/10 rounded-full blur-xl group-hover:opacity-30 transition-all duration-500 group-hover:scale-110"
        style={{
          transform: 'translate(-20%, 20%)'
        }}
      />
      <div className="portal-admin absolute bottom-0 left-0 w-24 h-24 bg-gradient-to-tr from-indigo-400/10 to-purple-400/10 rounded-full blur-xl group-hover:opacity-30 transition-all duration-500 group-hover:scale-110"
        style={{
          transform: 'translate(-20%, 20%)'
        }}
      />
      <div className="portal-teacher absolute bottom-0 left-0 w-24 h-24 bg-gradient-to-tr from-cyan-400/10 to-blue-400/10 rounded-full blur-xl group-hover:opacity-30 transition-all duration-500 group-hover:scale-110"
        style={{
          transform: 'translate(-20%, 20%)'
        }}
      />
      <div className="portal-student absolute bottom-0 left-0 w-24 h-24 bg-gradient-to-tr from-emerald-400/10 to-green-400/10 rounded-full blur-xl group-hover:opacity-30 transition-all duration-500 group-hover:scale-110"
        style={{
          transform: 'translate(-20%, 20%)'
        }}
      />

      {/* Content */}
      <div className="relative z-10">
        {/* Header */}
        {(title || Icon || action) && (
          <div className="flex items-center justify-between p-6 pb-4">
            <div className="flex items-center gap-3">
              {Icon && (
                <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-xl flex items-center justify-center shadow-md group-hover:scale-105 transition-all duration-300 group-hover:shadow-lg">
                  <Icon className="w-5 h-5 text-white" />
                </div>
              )}
              <div className="portal-admin">
                {Icon && (
                  <div className="w-10 h-10 bg-gradient-to-br from-purple-500 to-indigo-600 rounded-xl flex items-center justify-center shadow-md group-hover:scale-105 transition-all duration-300 group-hover:shadow-lg">
                    <Icon className="w-5 h-5 text-white" />
                  </div>
                )}
              </div>
              <div className="portal-teacher">
                {Icon && (
                  <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-cyan-600 rounded-xl flex items-center justify-center shadow-md group-hover:scale-105 transition-all duration-300 group-hover:shadow-lg">
                    <Icon className="w-5 h-5 text-white" />
                  </div>
                )}
              </div>
              <div className="portal-student">
                {Icon && (
                  <div className="w-10 h-10 bg-gradient-to-br from-green-500 to-emerald-600 rounded-xl flex items-center justify-center shadow-md group-hover:scale-105 transition-all duration-300 group-hover:shadow-lg">
                    <Icon className="w-5 h-5 text-white" />
                  </div>
                )}
              </div>
              <div>
                {title && (
                  <h3 className="text-lg font-bold text-black mb-1">
                    {title}
                  </h3>
                )}
                {subtitle && (
                  <p className="text-sm font-semibold text-black">
                    {subtitle}
                  </p>
                )}
              </div>
            </div>

            {action && (
              <div className="transform transition-transform duration-200 group-hover:scale-105">
                {action}
              </div>
            )}
          </div>
        )}

        {/* Content */}
        <div className={`${title || Icon || action ? 'px-6 pb-6' : 'p-6'}`}>
          {children}
        </div>
      </div>
    </div>
  );
};

export default Card;
